class Solution:
    def intersect(self, nums1, nums2):
        from collections import Counter
        if len(nums1) > len(nums2):
            nums1, nums2 = nums2, nums1
        cnt = Counter(nums1)
        res = []
        for v in nums2:
            if cnt.get(v, 0) > 0:
                res.append(v)
                cnt[v] -= 1
        return res

