var intersect = function(nums1, nums2) {
    if (nums1.length > nums2.length) { const t = nums1; nums1 = nums2; nums2 = t; }
    const cnt = new Map();
    for (const v of nums1) cnt.set(v, (cnt.get(v) || 0) + 1);
    const res = [];
    for (const v of nums2) {
        const c = cnt.get(v) || 0;
        if (c > 0) { res.push(v); cnt.set(v, c - 1); }
    }
    return res;
};
